#include <stdio.h>


int main()
{
    int n,a[3],i;
    scanf("%d %d %d %d",&n,&a[0],&a[1],&a[2]);

    int dp[n];
    for(i=0;i<n;i++){dp[i] = -1;}

    int j,c;
    for(i=0;i<3;i++)
    {
        j = 1;
        while(a[i]*j <= n)
        {
            if(dp[a[i]*j - 1]==(-1)){dp[a[i]*j - 1] = j;}
            for(c=0;c<n;c++)
            {
                if(dp[c]!=(-1) && c+a[i]*j < n)
                    { if(dp[c + a[i]*j] < dp[c] + j)
                    {dp[c + a[i]*j] = dp[c] + j;}}
            }
            j++;
        }
    }

    printf("%d",dp[n-1]);

    return 0;
}

