fn main() {
    let data = read_input();
    let (n, a, b, c) = (data[0], data[1], data[2], data[3]);

    let mut max_count = 0;

    let d = n / a;
    for i in 0..=d {
        let rem = n - a * i;
        let d = rem / b;
        for j in 0..=d {
            let rem = n - a * i - b * j;
            let d = rem / c;
            let x = a * i + b * j + c * d;
            let count = i + j + d;
            if x == n && count > max_count {
                max_count = count;
            }
        }
    }

    println!("{}", max_count);
}
fn read_input() -> Vec<isize> {
    let mut buffer = String::new();

    std::io::stdin()
        .read_line(&mut buffer)
        .expect("Failed to get input");

    buffer
        .trim()
        .split_whitespace()
        .map(|x| x.parse().expect("Failed to parse number"))
        .collect()
}
